import { Timer as TimerPrimitive, useTimer, useTimerContext } from '@ark-ui/react/timer';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef, ReactNode } from 'react';
import { Fragment, forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Timer.module.css';

const TimerRoot = forwardRef<
  ComponentRef<typeof TimerPrimitive.Root>,
  ComponentProps<typeof TimerPrimitive.Root>
>(function TimerRoot({ className, ...props }, ref) {
  return (
    <TimerPrimitive.Root
      ref={ref}
      data-slot="timer-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const TimerRootProvider = forwardRef<
  ComponentRef<typeof TimerPrimitive.RootProvider>,
  ComponentProps<typeof TimerPrimitive.RootProvider>
>(function TimerRootProvider({ className, ...props }, ref) {
  return (
    <TimerPrimitive.RootProvider
      ref={ref}
      data-slot="timer-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const TimerArea = forwardRef<
  ComponentRef<typeof TimerPrimitive.Area>,
  ComponentProps<typeof TimerPrimitive.Area>
>(function TimerArea({ className, ...props }, ref) {
  return (
    <TimerPrimitive.Area
      ref={ref}
      data-slot="timer-area"
      className={clsx(styles.area, normalizeClassName(className))}
      {...props}
    />
  );
});

const TimerItem = forwardRef<
  ComponentRef<typeof TimerPrimitive.Item>,
  ComponentProps<typeof TimerPrimitive.Item>
>(function TimerItem({ className, ...props }, ref) {
  return (
    <TimerPrimitive.Item
      ref={ref}
      data-slot="timer-item"
      className={clsx(styles.item, normalizeClassName(className))}
      {...props}
    />
  );
});

const TimerSeparator = forwardRef<
  ComponentRef<typeof TimerPrimitive.Separator>,
  ComponentProps<typeof TimerPrimitive.Separator>
>(function TimerSeparator({ className, ...props }, ref) {
  return (
    <TimerPrimitive.Separator
      ref={ref}
      data-slot="timer-separator"
      className={clsx(styles.separator, normalizeClassName(className))}
      {...props}
    />
  );
});

const TimerControl = forwardRef<
  ComponentRef<typeof TimerPrimitive.Control>,
  ComponentProps<typeof TimerPrimitive.Control>
>(function TimerControl({ className, ...props }, ref) {
  return (
    <TimerPrimitive.Control
      ref={ref}
      data-slot="timer-control"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    />
  );
});

const TimerActionTrigger = forwardRef<
  ComponentRef<typeof TimerPrimitive.ActionTrigger>,
  ComponentProps<typeof TimerPrimitive.ActionTrigger>
>(function TimerActionTrigger({ className, ...props }, ref) {
  return (
    <TimerPrimitive.ActionTrigger
      ref={ref}
      data-slot="timer-action-trigger"
      className={clsx(styles.actionTrigger, normalizeClassName(className))}
      {...props}
    />
  );
});

function TimerSegments({
  className,
  separator = ':',
  types,
}: {
  className?: string;
  separator?: ReactNode;
  types: ComponentProps<typeof TimerPrimitive.Item>['type'][];
}) {
  return (
    <TimerArea className={className}>
      {types.map((type, index) => (
        <Fragment key={`${type}-${index}`}>
          <TimerItem type={type} />
          {index < types.length - 1 && <TimerSeparator>{separator}</TimerSeparator>}
        </Fragment>
      ))}
    </TimerArea>
  );
}

const Timer = Object.assign(TimerRoot, {
  Root: TimerRoot,
  RootProvider: TimerRootProvider,
  Area: TimerArea,
  Item: TimerItem,
  Separator: TimerSeparator,
  Control: TimerControl,
  ActionTrigger: TimerActionTrigger,
  Context: TimerPrimitive.Context,
  Segments: TimerSegments,
});

export { Timer, useTimer, useTimerContext };

@layer moduix.components {
  .root {
    box-sizing: border-box;
    display: inline-grid;
    place-items: center;
    gap: var(--moduix-timer-gap, var(--moduix-spacing-3));
    width: var(--moduix-timer-width, max-content);
    color: var(--moduix-timer-color, var(--moduix-color-foreground));
  }

  .area {
    display: inline-flex;
    align-items: baseline;
    gap: var(--moduix-timer-area-gap, var(--moduix-spacing-1));
    font-size: var(--moduix-timer-area-font-size, var(--moduix-text-2xl));
    font-weight: var(--moduix-timer-area-font-weight, var(--moduix-weight-semibold));
    line-height: var(--moduix-timer-area-line-height, var(--moduix-line-height-text-sm));
    font-variant-numeric: tabular-nums;
    letter-spacing: 0;
  }

  .item {
    min-width: var(--moduix-timer-item-min-width, 2ch);
    color: var(--moduix-timer-item-color, currentColor);
    text-align: var(--moduix-timer-item-text-align, center);
  }

  .separator {
    color: var(--moduix-timer-separator-color, var(--moduix-color-muted-foreground));
  }

  .control {
    display: inline-flex;
    flex-wrap: wrap;
    align-items: center;
    gap: var(--moduix-timer-control-gap, var(--moduix-spacing-2));
  }

  .actionTrigger {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--moduix-timer-action-trigger-gap, var(--moduix-spacing-2));
    min-height: var(--moduix-timer-action-trigger-height, var(--moduix-size-md));
    margin: 0;
    border: var(--moduix-timer-action-trigger-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-timer-action-trigger-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-timer-action-trigger-radius, var(--moduix-radius-md));
    padding-block: var(--moduix-timer-action-trigger-padding-y, var(--moduix-spacing-1-5));
    padding-inline: var(--moduix-timer-action-trigger-padding-x, var(--moduix-spacing-3));
    background-color: var(--moduix-timer-action-trigger-bg, var(--moduix-color-background));
    color: var(--moduix-timer-action-trigger-color, var(--moduix-color-foreground));
    appearance: none;
    font: inherit;
    font-size: var(--moduix-timer-action-trigger-font-size, var(--moduix-text-sm));
    font-weight: var(--moduix-timer-action-trigger-font-weight, var(--moduix-weight-medium));
    line-height: var(--moduix-timer-action-trigger-line-height, var(--moduix-line-height-text-sm));
    white-space: nowrap;
    cursor: pointer;
    transition:
      background-color
        var(--moduix-timer-action-trigger-transition, var(--moduix-transition-default)),
      border-color var(--moduix-timer-action-trigger-transition, var(--moduix-transition-default)),
      color var(--moduix-timer-action-trigger-transition, var(--moduix-transition-default)),
      opacity var(--moduix-timer-action-trigger-transition, var(--moduix-transition-default)),
      box-shadow var(--moduix-timer-action-trigger-transition, var(--moduix-transition-default));

    @media (hover: hover) {
      &:hover {
        background-color: var(--moduix-timer-action-trigger-bg-hover, var(--moduix-color-accent));
      }
    }

    &:focus-visible {
      outline: var(
          --moduix-timer-action-trigger-focus-ring-width,
          var(--moduix-focus-ring-width, var(--moduix-border-width-md))
        )
        solid var(--moduix-timer-action-trigger-focus-ring-color, var(--moduix-color-ring));
      outline-offset: var(
        --moduix-timer-action-trigger-focus-ring-offset,
        var(--moduix-focus-ring-inset-offset)
      );
    }

    &:is(:disabled, [aria-disabled='true']) {
      opacity: var(--moduix-timer-action-trigger-disabled-opacity, var(--moduix-opacity-disabled));
      cursor: default;
      pointer-events: none;
    }

    &[hidden] {
      display: none;
    }

    & :where(svg) {
      width: var(--moduix-timer-action-trigger-icon-size, var(--moduix-spacing-4));
      height: var(--moduix-timer-action-trigger-icon-size, var(--moduix-spacing-4));
      flex-shrink: 0;
    }
  }
}
